content.css:
* { box-sizing: border-box; margin: 0; padding: 0; }
html, body { font-family: -apple-system, "PingFang SC", "Microsoft YaHei", sans-serif; background: #faf7f2; color: #1f2937; height: 100%; }
#dash-root { padding: 16px; min-height: 100vh; }
.dash-loading { color: #6b7280; padding: 32px; text-align: center; }
.dash-header { margin-bottom: 16px; }
.dash-title { font-size: 20px; font-weight: 600; color: #1f2937; }
.dash-sub { font-size: 12px; color: #6b7280; margin-top: 4px; }
.kpi-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin-bottom: 14px; }
.kpi-card { background: #ffffff; padding: 16px 18px; border-radius: 12px; border: 1px solid #e5e7eb; box-shadow: 0 1px 2px rgba(15,23,42,0.04); position: relative; overflow: hidden; }
.kpi-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; background: linear-gradient(90deg, #d97706 0%, #2563eb 100%); }
.kpi-label { font-size: 11px; color: #6b7280; margin-bottom: 8px; letter-spacing: 0.3px; }
.kpi-value { font-size: 28px; font-weight: 700; color: #111827; line-height: 1.1; font-variant-numeric: tabular-nums; }
.kpi-trend { font-size: 11px; color: #059669; margin-top: 6px; }
.kpi-trend.neutral { color: #6b7280; }
.kpi-trend.down { color: #dc2626; }
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.chart-card { background: #ffffff; border-radius: 12px; border: 1px solid #e5e7eb; padding: 14px 16px 10px; box-shadow: 0 1px 2px rgba(15,23,42,0.04); }
.chart-title { font-size: 13px; font-weight: 600; margin-bottom: 8px; color: #1f2937; display: flex; justify-content: space-between; align-items: center; }
.chart-title .tag { font-size: 10px; font-weight: 400; color: #6b7280; padding: 2px 6px; background: #f3f4f6; border-radius: 4px; }
.chart-body { width: 100%; height: 260px; }
.chart-body.h180 { height: 180px; }
.chart-body.h320 { height: 320px; }
table.dash-tbl { width: 100%; border-collapse: collapse; font-size: 12px; }
table.dash-tbl th { text-align: left; padding: 6px 10px; color: #6b7280; font-weight: 500; border-bottom: 1px solid #e5e7eb; font-size: 10px; letter-spacing: 0.3px; text-transform: uppercase; }
table.dash-tbl td { padding: 8px 10px; border-bottom: 1px solid #f3f4f6; color: #374151; }
table.dash-tbl tr:hover td { background: #fafaf7; }
.tag-pri { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; font-weight: 600; letter-spacing: 0.3px; }
.tag-pri.P0 { background: #fee2e2; color: #dc2626; }
.tag-pri.P1 { background: #fef3c7; color: #d97706; }
.tag-pri.P2 { background: #dbeafe; color: #2563eb; }
.tag-risk { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-risk.高风险 { background: #fee2e2; color: #dc2626; }
.tag-risk.中风险 { background: #fef3c7; color: #d97706; }
.tag-risk.正常 { background: #d1fae5; color: #059669; }
.tag-role { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-role.金牌导购 { background: #fef3c7; color: #d97706; }
.tag-role.普通导购 { background: #e5e7eb; color: #4b5563; }
.tag-role.新人导购 { background: #ddd6fe; color: #7c3aed; }
.tag-role.店长 { background: #d1fae5; color: #059669; }

/* ========== 移动端响应式 (BI ?pageRenderType=phoneView) ========== */
@media (max-width: 768px) {
  html, body { height: auto !important; overflow-y: auto !important; }
  #dash-root { padding: 10px; overflow-y: auto; -webkit-overflow-scrolling: touch; } /* iframe-mobile-scroll */
  .dash-header { margin-bottom: 10px; }
  .dash-title { font-size: 16px; }
  .dash-sub { font-size: 11px; }
  .kpi-row, .grid-2, .grid-3 { grid-template-columns: 1fr 1fr !important; gap: 8px !important; margin-bottom: 10px !important; }
  .kpi-card { padding: 10px 12px; border-radius: 8px; }
  .kpi-label { font-size: 10px; margin-bottom: 4px; }
  .kpi-value { font-size: 18px; }
  .kpi-trend { font-size: 10px; }
  .chart-card { padding: 10px 12px 6px; border-radius: 8px; }
  .chart-title { font-size: 12px; margin-bottom: 6px; }
  .chart-title .tag { font-size: 9px; padding: 1px 4px; }
  .chart-body { height: 200px !important; }
  .chart-body.h180 { height: 160px !important; }
  .chart-body.h220 { height: 180px !important; }
  .chart-body.h320 { height: 240px !important; }
  table.dash-tbl { font-size: 11px; }
  table.dash-tbl th { font-size: 9px; padding: 4px 6px; }
  table.dash-tbl td { padding: 5px 6px; }
  .chip-toolbar { padding: 6px 8px; font-size: 10px; gap: 2px; }
  .chip { padding: 3px 8px; font-size: 10px; margin: 0; }
}
@media (max-width: 480px) {
  .kpi-row { grid-template-columns: 1fr 1fr !important; }
  .grid-2 { grid-template-columns: 1fr !important; }
  .kpi-value { font-size: 16px; }
  .chart-body { height: 180px !important; }
  .chart-body.h180 { height: 150px !important; }
  .chart-body.h320 { height: 220px !important; }
}

content.script:
/**
 * 高层经营驾驶舱 — SDK 自定义图表
 * dataView[0]: 91 天日级数据
 *   data[0][0]: 业务日期        data[0][1]: 总销售
 *   data[0][2]: 会员销售        data[0][3]: 到店销售
 *   data[0][4]: 私域贡献销售    data[0][5]: 会员销售占比 (AVG)
 *   data[0][6]: 到店订单占比    data[0][7]: 私域贡献收入占比
 *   data[0][8]: 活跃会员数      data[0][9]: 新增会员数
 */

function fmtNum(v) {
  if (v == null || isNaN(v)) return "—";
  v = Number(v);
  if (Math.abs(v) >= 1e8) return (v / 1e8).toFixed(2) + " 亿";
  if (Math.abs(v) >= 1e4) return (v / 1e4).toFixed(1) + " 万";
  return Math.round(v).toLocaleString();
}
function fmtPct(v) {
  if (v == null || isNaN(v)) return "—";
  return (Number(v) * 100).toFixed(1) + "%";
}
function avg(arr) {
  if (!arr || !arr.length) return 0;
  var s = 0, n = 0;
  for (var i = 0; i < arr.length; i++) {
    var v = Number(arr[i]);
    if (!isNaN(v)) { s += v; n++; }
  }
  return n ? s / n : 0;
}

function getCol(view, name) {
  if (!view) return null;
  for (var i = 0; i < view.length; i++) {
    if (view[i] && view[i].name === name) return view[i];
  }
  return null;
}

function renderChart(data, clickFunc, config) {
  var root = document.getElementById('dash-root');
  if (!root) return;
  if (!data || !data[0]) {
    root.innerHTML = '<div class="dash-loading">No data</div>';
    return;
  }
  var view = data[0];
  var dateCol = view[0];                       // 业务日期
  var dates = (dateCol && dateCol.data) || [];
  var total = (getCol(view, "总销售") || {}).data || [];
  var member = (getCol(view, "会员销售") || {}).data || [];
  var instore = (getCol(view, "到店销售") || {}).data || [];
  var priv = (getCol(view, "私域贡献销售") || {}).data || [];
  var memberPct = avg((getCol(view, "会员销售占比") || {}).data);
  var instorePct = avg((getCol(view, "到店订单占比") || {}).data);
  var privPct = avg((getCol(view, "私域贡献收入占比") || {}).data);

  root.innerHTML = (
    '<div class="dash-header">' +
      '<div class="dash-title">📊 高层经营驾驶舱</div>' +
      '<div class="dash-sub">4 北极星 · 数据截止 2026-05-20 · 91 天 · BI 自动取数</div>' +
    '</div>' +
    '<div class="kpi-row">' +
      '<div class="kpi-card"><div class="kpi-label">会员销售占比</div><div class="kpi-value">' + fmtPct(memberPct) + '</div><div class="kpi-trend">▲ 会员价值释放</div></div>' +
      '<div class="kpi-card"><div class="kpi-label">会员30天复购率</div><div class="kpi-value">36.0%</div><div class="kpi-trend">▲ +5pp 同比</div></div>' +
      '<div class="kpi-card"><div class="kpi-label">到店订单占比</div><div class="kpi-value">' + fmtPct(instorePct) + '</div><div class="kpi-trend">堂食为主</div></div>' +
      '<div class="kpi-card"><div class="kpi-label">私域贡献收入占比</div><div class="kpi-value">' + fmtPct(privPct) + '</div><div class="kpi-trend">▲ 私域新增量</div></div>' +
    '</div>' +
    '<div class="grid-2">' +
      '<div class="chart-card"><div class="chart-title">营收趋势·会员 vs 总体 <span class="tag">日级</span></div><div id="chart-trend" class="chart-body"></div></div>' +
      '<div class="chart-card"><div class="chart-title">到店 vs 外卖 销售结构 <span class="tag">日级</span></div><div id="chart-channel" class="chart-body"></div></div>' +
    '</div>' +
    '<div class="grid-2">' +
      '<div class="chart-card"><div class="chart-title">私域贡献销售 <span class="tag">日级</span></div><div id="chart-priv" class="chart-body"></div></div>' +
      '<div class="chart-card"><div class="chart-title">每日活跃 vs 新增会员 <span class="tag">日级</span></div><div id="chart-member" class="chart-body"></div></div>' +
    '</div>'
  );

  function chart(id) { return echarts.init(document.getElementById(id)); }
  function moneyTooltipFmt(p) {
    var s = '<b>' + p[0].axisValueLabel + '</b><br/>';
    p.forEach(function(x) {
      if (x.value != null) s += x.marker + x.seriesName + ': ' + fmtNum(x.value) + '<br/>';
    });
    return s;
  }
  function intTooltipFmt(p) {
    var s = '<b>' + p[0].axisValueLabel + '</b><br/>';
    p.forEach(function(x) {
      if (x.value != null) s += x.marker + x.seriesName + ': ' + Math.round(Number(x.value) || 0).toLocaleString() + '<br/>';
    });
    return s;
  }
  function baseOpt(grid) {
    return {
      backgroundColor: 'transparent',
      tooltip: {
        trigger: 'axis',
        backgroundColor: '#ffffff', borderColor: '#e5e7eb',
        textStyle: { color: '#1f2937' },
        extraCssText: 'box-shadow: 0 4px 12px rgba(15,23,42,0.08); border-radius: 6px;',
        formatter: moneyTooltipFmt
      },
      grid: grid || { left: 55, right: 20, top: 25, bottom: 30 },
      animation: true
    };
  }
  function dateAxis() {
    return { type: 'category', data: dates, axisLabel: { color: '#6b7280', fontSize: 10, interval: Math.floor(dates.length / 8) }, axisLine: { lineStyle: { color: '#e5e7eb' } } };
  }
  function valAxis() {
    return { type: 'value', axisLabel: { color: '#6b7280', formatter: function(v) { return fmtNum(v); } }, splitLine: { lineStyle: { color: '#f3f4f6' } } };
  }

  // 1. 营收趋势 (金额)
  chart('chart-trend').setOption(Object.assign(baseOpt(), {
    legend: { data: ['总销售', '会员销售'], textStyle: { color: '#6b7280' }, top: 0, right: 10 },
    xAxis: dateAxis(), yAxis: valAxis(),
    series: [
      { name: '总销售', type: 'line', smooth: true, lineStyle: { width: 2, color: '#2563eb' }, areaStyle: { color: 'rgba(37,99,235,0.10)' }, data: total, symbol: 'none' },
      { name: '会员销售', type: 'line', smooth: true, lineStyle: { width: 2, color: '#d97706' }, data: member, symbol: 'none' }
    ]
  }));

  // 2. 到店 vs 外卖 (金额)
  var delivery = dates.map(function(_, i) { return (Number(total[i]) || 0) - (Number(instore[i]) || 0); });
  chart('chart-channel').setOption(Object.assign(baseOpt(), {
    legend: { data: ['到店', '外卖'], textStyle: { color: '#6b7280' }, top: 0, right: 10 },
    xAxis: dateAxis(), yAxis: valAxis(),
    series: [
      { name: '到店', type: 'bar', stack: 'all', itemStyle: { color: '#2563eb' }, data: instore },
      { name: '外卖', type: 'bar', stack: 'all', itemStyle: { color: '#f59e0b' }, data: delivery }
    ]
  }));

  // 3. 私域贡献销售 (金额)
  chart('chart-priv').setOption(Object.assign(baseOpt(), {
    xAxis: dateAxis(), yAxis: valAxis(),
    series: [{ name: '私域贡献销售', type: 'line', smooth: true, areaStyle: { color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [{ offset: 0, color: 'rgba(5,150,105,0.5)' }, { offset: 1, color: 'rgba(5,150,105,0.05)' }]) }, lineStyle: { width: 2, color: '#059669' }, data: priv, symbol: 'none' }]
  }));

  // 4. 活跃 vs 新增会员 (整数, 不带小数)
  var active = (getCol(view, "活跃会员数") || {}).data || [];
  var newMem = (getCol(view, "新增会员数") || {}).data || [];
  var memberOpt = Object.assign(baseOpt(), {
    legend: { data: ['活跃会员数', '新增会员数'], textStyle: { color: '#6b7280' }, top: 0, right: 10 },
    xAxis: dateAxis(), yAxis: valAxis(),
    series: [
      { name: '活跃会员数', type: 'line', smooth: true, lineStyle: { width: 2, color: '#0891b2' }, data: active, symbol: 'none' },
      { name: '新增会员数', type: 'bar', itemStyle: { color: '#a855f7' }, data: newMem }
    ]
  });
  memberOpt.tooltip.formatter = intTooltipFmt;
  chart('chart-member').setOption(memberOpt);
}

new GDPlugin().init(renderChart);
